  "import { dehydrateQueryClient } from '@netscript/fresh/query';\nimport { createNetScriptQueryClient } from '@netscript/sdk/query-client';\nimport { exampleServiceQueries } from '@app/lib/example-service.ts';\n\nexport const SERVICE_SHOWCASE_PAGE_SIZE = 3;\nexport const SERVICE_SHOWCASE_INPUT = {\n  limit: SERVICE_SHOWCASE_PAGE_SIZE,\n  offset: 0,\n} as const;\n\nexport type ServiceShowcaseListData = Awaited<ReturnType<typeof exampleServiceQueries.list>>;\n\nexport interface ServiceSummaryPanelProps {\n  readonly total: number;\n  readonly active: number;\n  readonly draft: number;\n  readonly archived: number;\n  readonly updatedAtLabel: string;\n}\n\ntype ServiceStatusCounts = {\n  active: number;\n  draft: number;\n  archived: number;\n};\n\nexport function formatServiceTimestamp(value: string | number): string {\n  return new Intl.DateTimeFormat('en', {\n    month: 'short',\n    day: 'numeric',\n    year: 'numeric',\n  }).format(new Date(value));\n}\n\nexport function buildServiceSummary(\n  data: ServiceShowcaseListData,\n  snapshotAt: number = Date.now(),\n): ServiceSummaryPanelProps {\n  const counts = data.items.reduce<ServiceStatusCounts>(\n    (summary, item) => {\n      summary[item.status] += 1;\n      return summary;\n    },\n    { active: 0, draft: 0, archived: 0 },\n  );\n\n  return {\n    total: data.total,\n    active: counts.active,\n    draft: counts.draft,\n    archived: counts.archived,\n    updatedAtLabel: formatServiceTimestamp(snapshotAt),\n  };\n}\n\nexport async function loadServiceShowcaseSummary(): Promise<ServiceSummaryPanelProps> {\n  const result = await exampleServiceQueries.list(SERVICE_SHOWCASE_INPUT);\n  return buildServiceSummary(result);\n}\n\nexport async function loadServiceShowcaseData() {\n  const queryClient = createNetScriptQueryClient();\n  const queryOptions = exampleServiceQueries.list.queryOptions(SERVICE_SHOWCASE_INPUT);\n  const cachedAt = Date.now();\n  const initialList = await queryClient.fetchQuery<ServiceShowcaseListData>({\n    queryKey: queryOptions.queryKey,\n    queryFn: queryOptions.queryFn,\n  });\n\n  return {\n    dehydratedState: dehydrateQueryClient(queryClient),\n    input: SERVICE_SHOWCASE_INPUT,\n    initialList,\n    cachedAt,\n  };\n}\n";
