const template_041 =
  "import { Button, Card } from '@app/components/ui/mod.ts';\nimport type { TelemetryTraceData, TelemetryTrace, TelemetrySpan } from '../(_shared)/telemetry-trace.ts';\n\ninterface TelemetryViewProps {\n  readonly data: TelemetryTraceData;\n  readonly examplesHref: string;\n}\n\nfunction SpanRow({ span }: { span: TelemetrySpan }) {\n  return (\n    <tr class='border-b border-ns-border/50 text-xs'>\n      <td class='px-3 py-2 font-mono text-ns-fg'>{span.name}</td>\n      <td class='px-3 py-2 text-ns-muted-fg'>{span.service}</td>\n      <td class='px-3 py-2 text-right font-mono text-ns-muted-fg'>{span.durationMs}ms</td>\n      <td class='px-3 py-2 font-mono text-ns-muted-fg/70'>{span.spanId.substring(0, 8)}</td>\n      <td class='px-3 py-2 font-mono text-ns-muted-fg/70'>\n        {span.parentSpanId ? span.parentSpanId.substring(0, 8) : '—'}\n      </td>\n    </tr>\n  );\n}\n\nfunction TraceCard({ trace }: { trace: TelemetryTrace }) {\n  return (\n    <Card>\n      <Card.Header>\n        <div class='flex items-center justify-between'>\n          <Card.Title>\n            <span class='font-mono text-sm'>{trace.traceId.substring(0, 16)}…</span>\n          </Card.Title>\n          {trace.isCrossService && (\n            <span class='rounded-full bg-green-500/10 px-2 py-0.5 text-xs font-medium text-green-600'>\n              cross-service\n            </span>\n          )}\n        </div>\n        <Card.Description>\n          {trace.spans.length} spans across {trace.services.join(', ')}\n        </Card.Description>\n      </Card.Header>\n      <Card.Body>\n        <div class='overflow-x-auto'>\n          <table class='w-full text-left'>\n            <thead>\n              <tr class='border-b border-ns-border text-xs font-medium uppercase tracking-wider text-ns-muted-fg'>\n                <th class='px-3 py-2'>Span</th>\n                <th class='px-3 py-2'>Service</th>\n                <th class='px-3 py-2 text-right'>Duration</th>\n                <th class='px-3 py-2'>Span ID</th>\n                <th class='px-3 py-2'>Parent</th>\n              </tr>\n            </thead>\n            <tbody>\n              {trace.spans.map((span) => <SpanRow span={span} />)}\n            </tbody>\n          </table>\n        </div>\n      </Card.Body>\n    </Card>\n  );\n}\n\nexport function TelemetryView({ data, examplesHref }: TelemetryViewProps) {\n  return (\n    <div class='min-h-[calc(100vh-52px)] bg-ns-bg text-ns-fg'>\n      <section class='ns-shell ns-section'>\n        <div class='ns-stack ns-stack--md'>\n          <div class='ns-stack ns-stack--xs'>\n            <div class='flex items-center gap-3'>\n              <Button type='link' href={examplesHref} variant='ghost' size='sm'>\n                &larr; Examples\n              </Button>\n            </div>\n            <span class='ns-badge ns-badge--secondary w-fit'>Telemetry</span>\n            <h1 class='text-3xl font-semibold text-ns-fg sm:text-4xl'>\n              Aspire Dashboard traces\n            </h1>\n            <p class='max-w-3xl text-sm leading-7 text-ns-muted-fg sm:text-base'>\n              Live traces from the Aspire Dashboard telemetry API. Fire a webhook to generate\n              a cross-service trace chain (trigger &rarr; queue &rarr; worker &rarr; job), then\n              refresh to see spans appear below.\n            </p>\n          </div>\n\n          <div class='flex flex-wrap items-center gap-4'>\n            <form method='POST'>\n              <Button type='submit' variant='primary' size='sm'>\n                Fire webhook trace\n              </Button>\n            </form>\n            <Button type='link' href={data.dashboardUrl} variant='outline' size='sm'>\n              Open Dashboard\n            </Button>\n            <span class='text-xs text-ns-muted-fg'>\n              {data.totalSpans} total spans &middot; {data.traces.length} traces shown\n            </span>\n          </div>\n\n          {data.error && (\n            <div class='rounded-lg border border-red-500/30 bg-red-500/5 px-4 py-3 text-sm text-red-400'>\n              Dashboard API error: {data.error}\n            </div>\n          )}\n\n          {data.traces.length === 0 && !data.error && (\n            <div class='rounded-lg border border-ns-border bg-ns-surface/60 px-4 py-8 text-center text-sm text-ns-muted-fg'>\n              No traces captured yet. Fire a webhook or trigger service calls to generate telemetry.\n            </div>\n          )}\n\n          <div class='ns-stack ns-stack--sm'>\n            {data.traces.map((trace) => <TraceCard trace={trace} />)}\n          </div>\n        </div>\n      </section>\n    </div>\n  );\n}\n";
const template_042 =
  "import { getServiceUrl } from '@netscript/sdk';\n\n// ---------------------------------------------------------------------------\n// Types\n// ---------------------------------------------------------------------------\n\nexport interface TelemetrySpan {\n  readonly traceId: string;\n  readonly spanId: string;\n  readonly parentSpanId: string;\n  readonly name: string;\n  readonly service: string;\n  readonly kind: number;\n  readonly durationMs: number;\n}\n\nexport interface TelemetryTrace {\n  readonly traceId: string;\n  readonly services: readonly string[];\n  readonly spans: readonly TelemetrySpan[];\n  readonly isCrossService: boolean;\n}\n\nexport interface TelemetryTraceData {\n  readonly traces: readonly TelemetryTrace[];\n  readonly totalSpans: number;\n  readonly dashboardUrl: string;\n  readonly error?: string;\n}\n\nexport interface WebhookFireResult {\n  readonly ok: boolean;\n  readonly status?: number;\n  readonly error?: string;\n}\n\n// ---------------------------------------------------------------------------\n// Dashboard API helpers\n// ---------------------------------------------------------------------------\n\ninterface OtlpSpan {\n  name: string;\n  kind: number;\n  traceId: string;\n  spanId: string;\n  parentSpanId: string;\n  startTimeUnixNano: string;\n  endTimeUnixNano: string;\n}\n\ninterface OtlpScopeSpans {\n  spans: OtlpSpan[];\n}\n\ninterface OtlpResource {\n  attributes: { key: string; value: { stringValue?: string } }[];\n}\n\ninterface OtlpResourceSpans {\n  scopeSpans: OtlpScopeSpans[];\n  resource: OtlpResource;\n}\n\ninterface DashboardTraceResponse {\n  data: { resourceSpans: OtlpResourceSpans[] };\n  totalCount: number;\n}\n\nfunction getDashboardBaseUrl(): string {\n  const port = Deno.env.get('ASPIRE_DASHBOARD_PORT') ?? '18888';\n  return `https://localhost:${port}`;\n}\n\nfunction getServiceName(resource: OtlpResource): string {\n  return (\n    resource.attributes.find((a) => a.key === 'service.name')?.value\n      .stringValue ?? 'unknown'\n  );\n}\n\nfunction nanoDuration(start: string, end: string): number {\n  return Math.round((Number(BigInt(end) - BigInt(start)) / 1_000_000));\n}\n\nexport async function fetchDashboardTraces(): Promise<TelemetryTraceData> {\n  const baseUrl = getDashboardBaseUrl();\n  const url = `${baseUrl}/api/telemetry/traces`;\n\n  try {\n    const resp = await fetch(url, {\n      headers: { Accept: 'application/json' },\n    });\n    if (!resp.ok) {\n      return { traces: [], totalSpans: 0, dashboardUrl: baseUrl, error: `Dashboard API ${resp.status}` };\n    }\n\n    const body = (await resp.json()) as DashboardTraceResponse;\n    const rs = body.data.resourceSpans;\n\n    const allSpans: TelemetrySpan[] = [];\n    for (const r of rs) {\n      const svc = getServiceName(r.resource);\n      for (const ss of r.scopeSpans) {\n        for (const span of ss.spans) {\n          allSpans.push({\n            traceId: span.traceId,\n            spanId: span.spanId,\n            parentSpanId: span.parentSpanId,\n            name: span.name,\n            service: svc,\n            kind: span.kind,\n            durationMs: nanoDuration(span.startTimeUnixNano, span.endTimeUnixNano),\n          });\n        }\n      }\n    }\n\n    const byTrace = new Map<string, TelemetrySpan[]>();\n    for (const s of allSpans) {\n      const arr = byTrace.get(s.traceId) ?? [];\n      arr.push(s);\n      byTrace.set(s.traceId, arr);\n    }\n\n    const traces: TelemetryTrace[] = [...byTrace.entries()]\n      .map(([traceId, spans]) => {\n        const services = [...new Set(spans.map((s) => s.service))];\n        return {\n          traceId,\n          services,\n          spans,\n          isCrossService: services.length > 1,\n        };\n      })\n      .sort((a, b) => b.spans.length - a.spans.length)\n      .slice(0, 20);\n\n    return { traces, totalSpans: allSpans.length, dashboardUrl: baseUrl };\n  } catch (err) {\n    const msg = err instanceof Error ? err.message : String(err);\n    return { traces: [], totalSpans: 0, dashboardUrl: baseUrl, error: msg };\n  }\n}\n\n// ---------------------------------------------------------------------------\n// Webhook trigger\n// ---------------------------------------------------------------------------\n\nexport async function fireWebhookTrace(): Promise<WebhookFireResult> {\n  try {\n    const triggersUrl = getServiceUrl('triggers-api', 'http');\n    const webhookUrl = `${triggersUrl}/api/v1/webhooks/inbound/generic`;\n    const resp = await fetch(webhookUrl, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        message: 'telemetry-page-trace',\n        timestamp: new Date().toISOString(),\n      }),\n    });\n    return { ok: resp.ok, status: resp.status };\n  } catch (err) {\n    return { ok: false, error: err instanceof Error ? err.message : String(err) };\n  }\n}\n";
