  "/**\n * {{__slot0__}} sample health-check job.\n *\n * Mirrors the main repo plugin job pattern with a small, safe handler that can\n * be triggered after the worker runtime is running.\n */\n\nimport {\n  createFailureResult,\n  createSuccessResult,\n  defineJobHandler,\n} from '@netscript/plugin-workers-core';\nimport { z } from 'zod';\n\nconst HealthCheckPayloadSchema = z.object({\n  verbose: z.boolean().default(false),\n});\n\ninterface HealthCheck {\n  name: string;\n  status: 'pass' | 'fail';\n  duration: number;\n  message: string;\n}\n\nconst handler = defineJobHandler(async (ctx) => {\n  HealthCheckPayloadSchema.parse(ctx.payload ?? {});\n  const startTime = performance.now();\n  const checks: HealthCheck[] = [];\n\n  console.info('Starting {{__slot2__}} sample health check');\n\n  await ctx.reportProgress?.(33, 'Checking runtime context');\n  checks.push({\n    name: 'context',\n    status: 'pass',\n    duration: performance.now() - startTime,\n    message: `Job context available: ${ctx.id}`,\n  });\n\n  await ctx.reportProgress?.(66, 'Checking filesystem access');\n  const fsStart = performance.now();\n  try {\n    const entries: string[] = [];\n    for await (const entry of Deno.readDir('.')) {\n      entries.push(entry.name);\n      if (entries.length >= 3) break;\n    }\n    checks.push({\n      name: 'filesystem',\n      status: 'pass',\n      duration: performance.now() - fsStart,\n      message: `Read ${entries.length} workspace entries`,\n    });\n  } catch (error) {\n    checks.push({\n      name: 'filesystem',\n      status: 'fail',\n      duration: performance.now() - fsStart,\n      message: error instanceof Error ? error.message : String(error),\n    });\n  }\n\n  await ctx.reportProgress?.(100, 'Complete');\n  const failed = checks.filter((check) => check.status === 'fail');\n  const result = {\n    plugin: '{{__slot4__}}',\n    status: failed.length === 0 ? 'healthy' : 'unhealthy',\n    checks,\n    totalDuration: performance.now() - startTime,\n    timestamp: new Date().toISOString(),\n  };\n\n  return failed.length === 0\n    ? createSuccessResult(result)\n    : createFailureResult(\n      `Sample health check failed: ${failed.map((check) => check.name).join(', ')}`,\n    );\n});\n\nexport default Object.assign(handler, { id: '{{__slot1__}}-health-check' });\n";
