const template_093 =
  "name: Build Bare-Metal Deploy Artifacts\n\non:\n  workflow_dispatch:\n    inputs:\n      environment:\n        description: Deployment environment represented by the artifact.\n        required: true\n        default: staging\n        type: choice\n        options:\n          - development\n          - staging\n          - production\n\npermissions:\n  contents: read\n\nconcurrency:\n  group: deploy-bare-metal-${{ github.event.inputs.environment || 'staging' }}\n  cancel-in-progress: false\n\njobs:\n  build:\n    strategy:\n      fail-fast: false\n      matrix:\n        include:\n          - os: ubuntu-latest\n            target: linux\n            deploy_dir: .deploy/linux\n          - os: windows-latest\n            target: windows\n            deploy_dir: .deploy/windows\n    runs-on: ${{ matrix.os }}\n    environment: ${{ github.event.inputs.environment || 'staging' }}\n    steps:\n      - uses: actions/checkout@v4\n\n      - uses: denoland/setup-deno@v2\n        with:\n          deno-version: v2.x\n\n      - name: Type-check workspace\n        run: deno task check\n\n      - name: Compile deployment artifacts\n        run: >\n          deno x -A jsr:@netscript/cli deploy build\n          --output-dir \"${{ matrix.deploy_dir }}\"\n\n      - uses: actions/upload-artifact@v4\n        with:\n          name: netscript-${{ matrix.target }}-${{ github.event.inputs.environment || 'staging' }}\n          path: ${{ matrix.deploy_dir }}\n          if-no-files-found: error\n";
const template_094 =
  "name: Deploy Compose to GHCR\n\non:\n  workflow_dispatch:\n    inputs:\n      environment:\n        description: GitHub/Aspire environment to deploy.\n        required: true\n        default: staging\n        type: choice\n        options:\n          - development\n          - staging\n          - production\n  push:\n    branches:\n      - main\n\npermissions:\n  contents: read\n  packages: write\n\nconcurrency:\n  group: deploy-compose-${{ github.event.inputs.environment || 'staging' }}\n  cancel-in-progress: false\n\njobs:\n  deploy:\n    runs-on: ubuntu-latest\n    environment: ${{ github.event.inputs.environment || 'staging' }}\n    env:\n      DEPLOY_ENVIRONMENT: ${{ github.event.inputs.environment || 'staging' }}\n      REGISTRY: ghcr.io\n      IMAGE_OWNER: ${{ github.repository_owner }}\n    steps:\n      - uses: actions/checkout@v4\n\n      - uses: denoland/setup-deno@v2\n        with:\n          deno-version: v2.x\n\n      - uses: docker/setup-buildx-action@v3\n\n      - uses: docker/login-action@v3\n        with:\n          registry: ghcr.io\n          username: ${{ github.actor }}\n          password: ${{ secrets.GITHUB_TOKEN }}\n\n      - name: Restore Aspire SDK\n        run: cd aspire && aspire restore\n\n      - name: Emit compose artifacts\n        run: >\n          deno x -A jsr:@netscript/cli deploy compose plan\n          --project-root .\n          --output-dir .deploy/compose\n          --environment \"$DEPLOY_ENVIRONMENT\"\n          --non-interactive\n\n      - name: Build and push compose images\n        run: |\n          docker compose -f .deploy/compose/docker-compose.yaml build\n          docker compose -f .deploy/compose/docker-compose.yaml push\n\n      - name: Deploy with Aspire without persisting plaintext state\n        run: >\n          deno x -A jsr:@netscript/cli deploy docker up\n          --project-root .\n          --environment \"$DEPLOY_ENVIRONMENT\"\n          --clear-cache\n          --non-interactive\n";
